import { useEffect, useMemo, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { registerUser } from "../services/api";
import { useAuth } from "../services/AuthContext";

const initialRegisterState = { name: "", age: "", gender: "male", username: "", password: "", mobile_number: "", email: "", location: "" };

export default function AuthPage({ initialMode = "login" }) {
  const [mode, setMode] = useState(initialMode);
  const [credentials, setCredentials] = useState({ username: "", password: "" });
  const [registerForm, setRegisterForm] = useState(initialRegisterState);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    setMode(initialMode);
  }, [initialMode]);

  const headline = useMemo(() => mode === "login" ? "Secure access to your intelligent healthcare workspace." : "Create your patient account through a premium onboarding flow.", [mode]);

  const handleLogin = async (event) => {
    event.preventDefault();
    try {
      setLoading(true);
      setError("");
      const user = await login(credentials);
      navigate(user.role === "admin" ? "/admin" : "/dashboard");
    } catch (err) {
      setError(err.response?.data?.detail || "Unable to sign in.");
    } finally {
      setLoading(false);
    }
  };

  const handleRegister = async (event) => {
    event.preventDefault();
    try {
      setLoading(true);
      setError("");
      await registerUser({ ...registerForm, age: Number(registerForm.age || 0) });
      setMode("login");
      setCredentials({ username: registerForm.username, password: registerForm.password });
    } catch (err) {
      const data = err.response?.data;
      setError(typeof data === "object" ? JSON.stringify(data) : "Unable to register.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-shell public-auth-shell premium-auth-shell">
      <div className="auth-backdrop-art" />
      <div className="auth-card public-auth-card premium-auth-card">
        <div className="hero-panel blue-hero-panel auth-showcase glossy-card">
          <span className="eyebrow">Healthcare Access</span>
          <h2>{mode === "login" ? "Login Portal" : "Registration Portal"}</h2>
          <p>{headline}</p>
          <div className="auth-art-grid">
            <div className="glass-panel auth-art-card large">AI triage and assistant-first guidance</div>
            <div className="glass-panel auth-art-card">Health records</div>
            <div className="glass-panel auth-art-card">Appointments</div>
            <div className="glass-panel auth-art-card">Admin visibility</div>
          </div>
          <div className="button-row">
            <Link className="btn btn-secondary" to="/">Back To Home</Link>
            <Link className="btn btn-secondary" to="/contact">Contact</Link>
          </div>
        </div>
        <div className="auth-form-panel public-card glossy-card">
          <div className="button-row auth-mode-switch" style={{ marginBottom: 16 }}>
            <button type="button" className={`btn ${mode === "login" ? "btn-primary neon-btn" : "btn-secondary"}`} onClick={() => setMode("login")}>Login</button>
            <button type="button" className={`btn ${mode === "register" ? "btn-primary neon-btn" : "btn-secondary"}`} onClick={() => setMode("register")}>Register</button>
          </div>
          {error ? <p className="error-text">{error}</p> : null}
          {mode === "login" ? (
            <form onSubmit={handleLogin}>
              <div className="field"><label>Username</label><input placeholder="Enter your username" value={credentials.username} onChange={(e) => setCredentials({ ...credentials, username: e.target.value })} /></div>
              <div className="field"><label>Password</label><div className="password-shell"><input type={showPassword ? "text" : "password"} placeholder="Enter your password" value={credentials.password} onChange={(e) => setCredentials({ ...credentials, password: e.target.value })} /><button type="button" className="password-toggle" onClick={() => setShowPassword((current) => !current)}>{showPassword ? "Hide" : "Show"}</button></div></div>
              <button className="btn btn-primary neon-btn" disabled={loading} type="submit">{loading ? "Signing in..." : "Login"}</button>
              <p className="muted auth-footnote">Don�t have an account? <Link to="/register">Register</Link></p>
            </form>
          ) : (
            <form onSubmit={handleRegister}>
              <div className="auth-form-groups">
                <div className="public-card auth-group-card">
                  <h3>Identity</h3>
                  <div className="form-grid">
                    <div className="field"><label>Name</label><input value={registerForm.name} onChange={(e) => setRegisterForm({ ...registerForm, name: e.target.value })} /></div>
                    <div className="field"><label>Age</label><input type="number" value={registerForm.age} onChange={(e) => setRegisterForm({ ...registerForm, age: e.target.value })} /></div>
                    <div className="field"><label>Gender</label><select value={registerForm.gender} onChange={(e) => setRegisterForm({ ...registerForm, gender: e.target.value })}><option value="male">Male</option><option value="female">Female</option><option value="other">Other</option></select></div>
                  </div>
                </div>
                <div className="public-card auth-group-card">
                  <h3>Credentials</h3>
                  <div className="form-grid">
                    <div className="field"><label>Username</label><input value={registerForm.username} onChange={(e) => setRegisterForm({ ...registerForm, username: e.target.value })} /></div>
                    <div className="field"><label>Password</label><div className="password-shell"><input type={showPassword ? "text" : "password"} value={registerForm.password} onChange={(e) => setRegisterForm({ ...registerForm, password: e.target.value })} /><button type="button" className="password-toggle" onClick={() => setShowPassword((current) => !current)}>{showPassword ? "Hide" : "Show"}</button></div></div>
                  </div>
                </div>
                <div className="public-card auth-group-card">
                  <h3>Contact Details</h3>
                  <div className="form-grid">
                    <div className="field"><label>Mobile Number</label><input value={registerForm.mobile_number} onChange={(e) => setRegisterForm({ ...registerForm, mobile_number: e.target.value })} /></div>
                    <div className="field"><label>Email</label><input type="email" value={registerForm.email} onChange={(e) => setRegisterForm({ ...registerForm, email: e.target.value })} /></div>
                    <div className="field"><label>Location</label><input value={registerForm.location} onChange={(e) => setRegisterForm({ ...registerForm, location: e.target.value })} /></div>
                  </div>
                </div>
              </div>
              <button className="btn btn-primary neon-btn" disabled={loading} type="submit">{loading ? "Creating account..." : "Register"}</button>
              <p className="muted auth-footnote">Already registered? <Link to="/login">Login</Link></p>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}
